pragma solidity =0.8.24;

import { ILendingPoolV2 } from "../../../interfaces/protocols/aaveV2/ILendingPoolV2.sol";
import {
    ILendingPoolAddressesProviderV2
} from "../../../interfaces/protocols/aaveV2/ILendingPoolAddressesProviderV2.sol";
import { DSMath } from "../../../_vendor/DS/DSMath.sol";
import { MainnetAaveAddresses } from "./MainnetAaveAddresses.sol";

contract AaveRatioHelper is DSMath, MainnetAaveAddresses {
    function getSafetyRatio(address _market, address _user) public view returns (uint256) {
        ILendingPoolV2 lendingPool =
            ILendingPoolV2(ILendingPoolAddressesProviderV2(_market).getLendingPool());

        (, uint256 totalDebtETH, uint256 availableBorrowsETH,,,) =
            lendingPool.getUserAccountData(_user);

        if (totalDebtETH == 0) return uint256(0);

        return wdiv(add(totalDebtETH, availableBorrowsETH), totalDebtETH);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import {ERC20} from "../../token/ERC20/ERC20.sol";
import {Address} from "../../utils/Address.sol";

contract ERC20Reentrant is ERC20("TEST", "TST") {
    enum Type {
        No,
        Before,
        After
    }

    Type private _reenterType;
    address private _reenterTarget;
    bytes private _reenterData;

    function scheduleReenter(Type when, address target, bytes calldata data) external {
        _reenterType = when;
        _reenterTarget = target;
        _reenterData = data;
    }

    function functionCall(address target, bytes memory data) public returns (bytes memory) {
        return Address.functionCall(target, data);
    }

    function _update(address from, address to, uint256 amount) internal override {
        if (_reenterType == Type.Before) {
            _reenterType = Type.No;
            functionCall(_reenterTarget, _reenterData);
        }
        super._update(from, to, amount);
        if (_reenterType == Type.After) {
            _reenterType = Type.No;
            functionCall(_reenterTarget, _reenterData);
        }
    }
}
